// Main control coordination logic
const devices = global.get('devices') || {};
const control = global.get('control') || {
    zeroExportThreshold: 50,
    loadShareRampRate: 1.0,
    gensetMinRunTime: 300,
    gensetCooldownTime: 120,
    pvPriority: true,
    gensetRunning: false,
    lastGensetStop: 0
};

const now = Date.now();
const huawei = devices['Huawei SmartLogger 3000A'] || {};
const gc600 = devices['SICES GC600'] || {};
const mc200 = devices['SICES MC200'] || {};

// Calculate total system parameters
const pvPower = parseFloat(huawei.active_power) || 0;
const gensetPower = parseFloat(gc600.active_power) || 0;
const gridPower = parseFloat(mc200.active_power_total) || 0;
const exportPower = mc200.is_exporting ? Math.abs(gridPower) : 0;
const importPower = mc200.is_importing ? gridPower : 0;

// Total load calculation
const totalLoad = pvPower + gensetPower - exportPower + importPower;

const controlData = {
    timestamp: new Date().toISOString(),
    system_status: {
        pv_power: pvPower,
        genset_power: gensetPower,
        grid_power: gridPower,
        export_power: exportPower,
        import_power: importPower,
        total_load: totalLoad
    },
    control_decisions: []
};

// Zero Export Control Logic
if (exportPower > control.zeroExportThreshold) {
    const excessPower = exportPower;

    // First priority: Curtail PV if possible
    if (pvPower > excessPower) {
        const newPvLimit = Math.max(10, 100 - (excessPower / pvPower * 100));
        controlData.control_decisions.push({
            device: 'Huawei SmartLogger 3000A',
            action: 'set_power_limit',
            value: newPvLimit,
            reason: 'zero_export_protection',
            priority: 1
        });
    }

    // Second priority: Increase genset load if running
    if (control.gensetRunning && gensetPower < totalLoad) {
        const gensetIncrease = Math.min(excessPower, totalLoad - gensetPower);
        const newGensetSetpoint = Math.min(100, (gensetPower + gensetIncrease) / totalLoad * 100);
        controlData.control_decisions.push({
            device: 'SICES GC600',
            action: 'set_power_setpoint',
            value: newGensetSetpoint,
            reason: 'absorb_excess_pv',
            priority: 2
        });
    }
}

// Load Sharing Logic with PV Priority
if (control.pvPriority && totalLoad > 0) {
    const pvContribution = (pvPower / totalLoad * 100).toFixed(1);
    const gensetContribution = (gensetPower / totalLoad * 100).toFixed(1);
    const gridContribution = (Math.abs(gridPower) / totalLoad * 100).toFixed(1);

    controlData.load_sharing = {
        pv_contribution: pvContribution,
        genset_contribution: gensetContribution,
        grid_contribution: gridContribution
    };

    // Genset management based on load and PV availability
    const pvAvailabilityRatio = pvPower / totalLoad;

    // Start genset if PV can't meet load and grid import is high
    if (!control.gensetRunning && 
        pvAvailabilityRatio < 0.7 && 
        importPower > 50 &&
        now - control.lastGensetStop > control.gensetCooldownTime * 1000) {

        controlData.control_decisions.push({
            device: 'SICES GC600',
            action: 'start_genset',
            value: 1,
            reason: 'insufficient_pv_high_import',
            priority: 1
        });
        control.gensetRunning = true;
        control.gensetStartTime = now;
    }

    // Stop genset if PV can meet most of the load
    if (control.gensetRunning && 
        pvAvailabilityRatio > 0.9 &&
        now - control.gensetStartTime > control.gensetMinRunTime * 1000) {

        controlData.control_decisions.push({
            device: 'SICES GC600',
            action: 'stop_genset',
            value: 0,
            reason: 'sufficient_pv_available',
            priority: 1
        });
        control.gensetRunning = false;
        control.lastGensetStop = now;
    }
}

// Gradual Genset Ramp Logic
if (control.gensetRunning) {
    const currentGensetLoad = gensetPower / totalLoad * 100 || 0;
    const targetGensetLoad = Math.max(20, Math.min(80, 100 - (pvPower / totalLoad * 100)));

    if (Math.abs(targetGensetLoad - currentGensetLoad) > 5) {
        const rampDirection = targetGensetLoad > currentGensetLoad ? 1 : -1;
        const rampStep = control.loadShareRampRate * rampDirection;
        const newSetpoint = Math.max(0, Math.min(100, currentGensetLoad + rampStep));

        controlData.control_decisions.push({
            device: 'SICES GC600',
            action: 'gradual_ramp',
            value: newSetpoint,
            reason: 'load_balancing',
            priority: 3
        });
    }
}

// Save control state
global.set('control', control);

msg.payload = controlData;
return msg;

// Dispatch control commands to appropriate devices
const controlData = msg.payload;
const decisions = controlData.control_decisions || [];

// Sort decisions by priority
decisions.sort((a, b) => a.priority - b.priority);

const commands = [];

decisions.forEach(decision => {
    let command = {
        timestamp: new Date().toISOString(),
        device: decision.device,
        action: decision.action,
        value: decision.value,
        reason: decision.reason,
        priority: decision.priority
    };

    // Map to specific Modbus commands
    switch(decision.device) {
        case 'Huawei SmartLogger 3000A':
            if (decision.action === 'set_power_limit') {
                command.modbus = {
                    function: 'writeHoldingRegisters',
                    address: 47415,
                    value: Math.round(decision.value * 10), // Scale for register
                    quantity: 1
                };
            }
            break;

        case 'SICES GC600':
            if (decision.action === 'start_genset') {
                command.modbus = {
                    function: 'writeHoldingRegisters',
                    address: 1000,
                    value: 1,
                    quantity: 1
                };
            } else if (decision.action === 'stop_genset') {
                command.modbus = {
                    function: 'writeHoldingRegisters',
                    address: 1000,
                    value: 0,
                    quantity: 1
                };
            } else if (decision.action === 'set_power_setpoint' || decision.action === 'gradual_ramp') {
                command.modbus = {
                    function: 'writeHoldingRegisters',
                    address: 1001,
                    value: Math.round(decision.value * 10), // Scale for register
                    quantity: 1
                };
            }
            break;

        case 'SICES MC200':
            if (decision.action === 'mgcb_control') {
                command.modbus = {
                    function: 'writeHoldingRegisters',
                    address: 1000,
                    value: decision.value,
                    quantity: 1
                };
            } else if (decision.action === 'export_enable') {
                command.modbus = {
                    function: 'writeHoldingRegisters', 
                    address: 1001,
                    value: decision.value,
                    quantity: 1
                };
            }
            break;
    }

    commands.push(command);
});

msg.payload = {
    system_status: controlData.system_status,
    load_sharing: controlData.load_sharing,
    commands: commands,
    timestamp: controlData.timestamp
};

return msg;

// Execute Modbus write commands
const data = msg.payload;
const commands = data.commands || [];

commands.forEach((command, index) => {
    if (command.modbus) {
        // Prepare message for Modbus write
        const writeMsg = {
            topic: `command/${command.device.replace(/\s+/g, '_').toLowerCase()}`,
            payload: {
                device: command.device,
                function: command.modbus.function,
                address: command.modbus.address,
                value: command.modbus.value,
                quantity: command.modbus.quantity,
                timestamp: command.timestamp,
                reason: command.reason,
                priority: command.priority
            }
        };

        // Send with delay to avoid command conflicts
        setTimeout(() => {
            node.send(writeMsg);
        }, index * 100);
    }
});

return null;
